2383 InstructionCost VPWidenRecipe::computeCost(ElementCount VF,
2384                                            VPCostContext &Ctx) const {
2385   switch (Opcode) {
2386   case Instruction::UDiv:
2387   case Instruction::SDiv:
2388   case Instruction::SRem:
2389   case Instruction::URem:
2390     // If the div/rem operation isn't safe to speculate and requires
2391     // predication, then the only way we can even create a vplan is to insert
2392     // a select on the second input operand to ensure we use the value of 1
2393     // for the inactive lanes. The select will be costed separately.
2394   case Instruction::FNeg:
2395   case Instruction::Add:
2396   case Instruction::FAdd:
2397   case Instruction::Sub:
2398   case Instruction::FSub:
2399   case Instruction::Mul:
2400   case Instruction::FMul:
2401   case Instruction::FDiv:
2402   case Instruction::FRem:
2403   case Instruction::Shl:
2404   case Instruction::LShr:
2405   case Instruction::AShr:
2406   case Instruction::And:
2407   case Instruction::Or:
2408   case Instruction::Xor:
2409   case Instruction::Freeze:
2410   case Instruction::ExtractValue:
2411   case Instruction::ICmp:
2412   case Instruction::FCmp:
2413   case Instruction::Select:
2414     return getCostForRecipeWithOpcode(getOpcode(), VF, Ctx);
2415   default:
2416     llvm_unreachable("Unsupported opcode for instruction");
2417   }
